private func compactMetadata(_ metadata: [String: String?]) -> [String: String] {
    metadata.reduce(into: [String: String]()) { partialResult, pair in
        if let value = pair.value, !value.isEmpty {
            partialResult[pair.key] = value
        }
    }
}

private func redactEmail(_ email: String?) -> String? {
    guard let email, !email.isEmpty else { return nil }
    let parts = email.split(separator: "@")
    guard parts.count == 2 else { return "<redacted_email>" }
    let local = String(parts[0])
    let domain = String(parts[1])
    let visiblePrefix = local.prefix(1)
    return "\(visiblePrefix)***@\(domain)"
}

private func redactIdentifier(_ value: String?) -> String? {
    guard let value, !value.isEmpty else { return nil }
    if value.count <= 4 {
        return "****"
    }
    let suffix = value.suffix(4)
    return "****\(suffix)"
}

private func sanitizeEndpoint(_ endpoint: String) -> String {
    guard let components = URLComponents(string: endpoint) else {
        return endpoint
    }
    var sanitized = components
    if let queryItems = sanitized.queryItems, !queryItems.isEmpty {
        sanitized.queryItems = queryItems.map { item in
            let lowercasedName = item.name.lowercased()
            let sensitiveKeys = ["token", "auth", "authorization", "email", "user_id", "userid", "password", "secret"]
            if sensitiveKeys.contains(where: { lowercasedName.contains($0) }) {
                return URLQueryItem(name: item.name, value: "<redacted>")
            }
            return item
        }
    }
    return sanitized.string ?? endpoint
}

public final class APIRequestTracker {
    public static let shared = APIRequestTracker()

    private init() {}

    public func performTrackedRequest(
        endpoint: String,
        method: String,
        requestID: String? = UUID().uuidString,
        operation: (@escaping (Result<(statusCode: Int, payloadSummary: String?), Error>) -> Void) -> Void
    ) {
        let start = Date()
        AppAnalyticsDebugger.shared.trackRequestStarted(endpoint: endpoint, method: method, requestID: requestID)

        operation { result in
            let duration = Date().timeIntervalSince(start)
            switch result {
            case .success(let response):
                AppAnalyticsDebugger.shared.logEvent(
                    AnalyticsEvent(
                        category: .api,
                        name: "request_response",
                        metadata: compactMetadata([
                            "endpoint": sanitizeEndpoint(endpoint),
                            "method": method.uppercased(),
                            "status_code": String(response.statusCode),
                            "duration_ms": String(Int(duration * 1000)),
                            "request_id": requestID,
                            "payload_summary": response.payloadSummary
                        ])
                    )
                )
            case .failure(let error):
                AppAnalyticsDebugger.shared.trackError(error, context: "api_request:\(sanitizeEndpoint(endpoint))", code: nil)
                AppAnalyticsDebugger.shared.logEvent(
                    AnalyticsEvent(
                        category: .api,
                        name: "request_failed",
                        metadata: compactMetadata([
                            "endpoint": sanitizeEndpoint(endpoint),
                            "method": method.uppercased(),
                            "duration_ms": String(Int(duration * 1000)),
                            "request_id": requestID
                        ])
                    )
                )
            }
        }
    }
}

