public enum AppDebugEvent {
    case appLaunch
    case appBackground
    case appForeground
    case loginSuccess(userID: String?, email: String?)
    case loginFailure(reason: String?)
    case apiSuccess(endpoint: String, method: String, statusCode: Int, duration: TimeInterval, requestID: String?)
    case apiFailure(endpoint: String, method: String, error: Error, requestID: String?)
    case profileUpdated(field: String, userID: String?)
    case interaction(screen: String, action: String, element: String?)
}

public extension AppAnalyticsDebugger {
    func handle(_ event: AppDebugEvent) {
        switch event {
        case .appLaunch:
            trackAppLifecycle(state: "launch")
        case .appBackground:
            trackAppLifecycle(state: "background")
        case .appForeground:
            trackAppLifecycle(state: "foreground")
        case .loginSuccess(let userID, let email):
            trackAuthenticationSuccess(userID: userID, email: email)
        case .loginFailure(let reason):
            trackAuthenticationFailure(reason: reason)
        case .apiSuccess(let endpoint, let method, let statusCode, let duration, let requestID):
            trackRequestCompleted(endpoint: endpoint, method: method, statusCode: statusCode, duration: duration, requestID: requestID)
        case .apiFailure(let endpoint, _, let error, _):
            trackError(error, context: "api_failure:\(sanitizeEndpoint(endpoint))", code: nil)
        case .profileUpdated(let field, let userID):
            trackUserDataChange(field: field, action: "update", userID: userID)
        case .interaction(let screen, let action, let element):
            trackInteraction(screen: screen, action: action, element: element)
        }
    }
}